const ESTIMATE_GAESAN_MANUAL_WIDTH_UNITS = [17.47, 8.13, 9.63, 6, 20.24, 20.24, 18.13, 8.38, 8.38, 12, 8.38, 8.38, 8.38, 8.38, 8.38];
