    starts[estimateSheetCellKey(r1, c1)] = { rowspan: r2 - r1 + 1, colspan: c2 - c1 + 1 };
    for (let r = r1; r <= r2; r += 1) for (let c = c1; c <= c2; c += 1) if (r !== r1 || c !== c1) skips.add(estimateSheetCellKey(r, c));
