function estimateSheetBindExcelWindow(win) {
  const doc = win.document;
  doc.getElementById("estimateSheetPopupSaveBtn")?.addEventListener("click", () => {
    const active = doc.querySelector("#estimateSheetPopupGrid .estimate-excel-cell.active-cell");
    if (active) estimateSheetPopupUpdateCellFromElement(active);
    saveEstimateSheetRecord();
    win.close();
  });
  doc.getElementById("estimateSheetPopupUploadBtn")?.addEventListener("click", () => {
    doc.getElementById("estimateSheetPopupUploadInput")?.click();
  });
  doc.getElementById("estimateSheetPopupUploadInput")?.addEventListener("change", event => {
    handleEstimateSheetExcelUpload(event.target);
  });
  doc.getElementById("estimateSheetPopupPdfBtn")?.addEventListener("click", () => {
    const active = doc.querySelector("#estimateSheetPopupGrid .estimate-excel-cell.active-cell");
    if (active) estimateSheetPopupUpdateCellFromElement(active);
    estimateSheetPrintCurrentPdf();
  });
  doc.getElementById("estimateSheetPopupResetBtn")?.addEventListener("click", () => {
    estimateSheetEditorState = estimateSheetCreateState(estimateSheetActiveType);
    estimateSheetExcelActiveCell = { r: 1, c: 1 };
    estimateSheetRenderExcelWindow();
  });
  doc.getElementById("estimateSheetPopupAddRowBtn")?.addEventListener("click", () => estimateSheetPopupInsertRow(estimateSheetExcelActiveCell.r));
  doc.getElementById("estimateSheetPopupAddColBtn")?.addEventListener("click", () => estimateSheetPopupInsertCol(estimateSheetExcelActiveCell.c));
  doc.getElementById("estimateSheetPopupExportBtn")?.addEventListener("click", () => exportEstimateSheetCurrentHtml());
  doc.getElementById("estimateSheetFormulaBox")?.addEventListener("keydown", event => {
    if (event.key !== "Enter") return;
    event.preventDefault();
    estimateSheetSetCellFromText(estimateSheetExcelActiveCell.r, estimateSheetExcelActiveCell.c, event.target.value);
    estimateSheetRenderExcelWindow();
  });
  doc.addEventListener("focusin", event => {
    const cell = event.target.closest?.(".estimate-excel-cell");
    if (cell) estimateSheetPopupSelectCell(Number(cell.dataset.row), Number(cell.dataset.col), false);
  });
  doc.addEventListener("input", event => {
    const cell = event.target.closest?.(".estimate-excel-cell");
    if (cell) estimateSheetPopupSelectCell(Number(cell.dataset.row), Number(cell.dataset.col), false, cell.innerText);
  });
  doc.addEventListener("contextmenu", event => {
    const cell = event.target.closest?.(".estimate-excel-cell");
    const head = event.target.closest?.(".estimate-excel-col-head");
    let col = null;
    if (cell) col = Number(cell.dataset.col);
    if (!col && head) col = Array.from(head.parentElement.children).indexOf(head);
    if (!col || !estimateSheetEditorState) return;
    event.preventDefault();
    const px = Number(estimateSheetEditorState.colWidths[col - 1] || 64);
    const unit = estimateSheetWidthUnitFromCol(estimateSheetEditorState, col);
    win.alert(`${estimateSheetColumnLabel(col - 1)}열 너비: ${unit} (웹 ${Math.round(px)}px)`);
  });
  doc.addEventListener("keydown", event => {
    const cell = event.target.closest?.(".estimate-excel-cell");
    if (!cell) return;
    if (event.ctrlKey && event.shiftKey && event.key === "F9") {
      event.preventDefault();
      updateEstimateSheetCell(cell);
      estimateSheetPopupInsertCol(Number(cell.dataset.col));
      return;
    }
    if (event.ctrlKey && event.key === "F9") {
      event.preventDefault();
      updateEstimateSheetCell(cell);
      estimateSheetPopupInsertRow(Number(cell.dataset.row));
      return;
    }
    if ((event.key === "Delete" || event.key === "Backspace") && !cell.isContentEditable) {
      event.preventDefault();
      estimateSheetSetCellFromText(Number(cell.dataset.row), Number(cell.dataset.col), "");
      cell.textContent = "";
      estimateSheetPopupSelectCell(Number(cell.dataset.row), Number(cell.dataset.col), true);
      return;
    }
    if (["Enter", "Tab", "ArrowUp", "ArrowDown", "ArrowLeft", "ArrowRight"].includes(event.key)) {
      event.preventDefault();
      estimateSheetPopupUpdateCellFromElement(cell);
      const map = { Enter: [event.shiftKey ? -1 : 1, 0], Tab: [0, event.shiftKey ? -1 : 1], ArrowUp: [-1, 0], ArrowDown: [1, 0], ArrowLeft: [0, -1], ArrowRight: [0, 1] };
      const [dr, dc] = map[event.key];
      estimateSheetPopupMoveFocus(Number(cell.dataset.row) + dr, Number(cell.dataset.col) + dc);
    }
  });
  win.addEventListener("beforeunload", () => { if (estimateSheetExcelWindowRef === win) estimateSheetExcelWindowRef = null; });
}

function estimateSheetPopupSelectCell(r, c, focus = true, liveText = null) {
  const win = estimateSheetExcelWindowRef;
  if (!win || win.closed || !estimateSheetEditorState) return;
  const doc = win.document;
  const row = Math.max(1, Math.min(estimateSheetEditorState.maxRow, Number(r) || 1));
  const col = Math.max(1, Math.min(estimateSheetEditorState.maxCol, Number(c) || 1));
  estimateSheetExcelActiveCell = { r: row, c: col };
  doc.querySelectorAll(".estimate-excel-cell.active-cell").forEach(el => el.classList.remove("active-cell"));
  const cell = doc.querySelector(`#estimateSheetPopupGrid [data-row="${row}"][data-col="${col}"]`);
  cell?.classList.add("active-cell");
  if (focus && cell) {
    cell.focus();
    const selection = win.getSelection?.();
    const range = doc.createRange?.();
    if (selection && range) {
      range.selectNodeContents(cell);
      selection.removeAllRanges();
      selection.addRange(range);
    }
  }
  const nameBox = doc.getElementById("estimateSheetNameBox");
  const formulaBox = doc.getElementById("estimateSheetFormulaBox");
  const obj = estimateSheetGetCellObj(estimateSheetEditorState, row, col);
  if (nameBox) nameBox.value = `${estimateSheetColumnLabel(col - 1)}${row}`;
  if (formulaBox) formulaBox.value = liveText !== null ? liveText : (obj.formula ? `=${obj.formula}` : estimateSheetDisplayValue(estimateSheetEditorState, row, col));
}

function estimateSheetSetCellFromText(r, c, rawText, option = {}) {
  if (!estimateSheetEditorState) return;
  const obj = estimateSheetGetCellObj(estimateSheetEditorState, r, c);
  const raw = String(rawText ?? "").replace(/ /g, " ").trim();
  if (option.keepFormulaWhenUnchanged && obj.formula) {
    const displayed = String(estimateSheetDisplayValue(estimateSheetEditorState, r, c)).replace(/ /g, " ").trim();
    if (raw === displayed) return;
  }
  if (raw.startsWith("=")) {
    obj.formula = raw.slice(1);
    obj.userFormula = true;
    obj.value = "";
  } else {
    obj.formula = "";
    obj.userFormula = false;
    obj.value = /^-?[\d,]+(\.\d+)?$/.test(raw) ? Number(raw.replace(/,/g, "")) : raw;
  }
}

function estimateSheetPopupUpdateCellFromElement(cell) {
  if (!cell) return;
  estimateSheetSetCellFromText(Number(cell.dataset.row), Number(cell.dataset.col), cell.innerText, { keepFormulaWhenUnchanged: true });
}

function estimateSheetPopupMoveFocus(r, c) {
  if (!estimateSheetEditorState) return;
  const row = Math.max(1, Math.min(estimateSheetEditorState.maxRow, Number(r) || 1));
  const col = Math.max(1, Math.min(estimateSheetEditorState.maxCol, Number(c) || 1));
  estimateSheetExcelActiveCell = { r: row, c: col };
  estimateSheetRenderExcelWindow();
  estimateSheetPopupSelectCell(row, col, true);
  const win = estimateSheetExcelWindowRef;
  const cell = win?.document?.querySelector(`#estimateSheetPopupGrid [data-row="${row}"][data-col="${col}"]`);
  cell?.scrollIntoView?.({ block: "nearest", inline: "nearest" });
}

function estimateSheetPopupInsertRow(afterRow) {
  estimateSheetInsertRow(afterRow);
  estimateSheetRenderExcelWindow();
}

function estimateSheetPopupInsertCol(afterCol) {
  estimateSheetInsertCol(afterCol);
  estimateSheetRenderExcelWindow();
}

function openEstimateSheetExcelWindow(index = null, option = {}) {
  estimateSheetEnsureDefaultRecords();
  if (index !== null && estimateSheetRecords[index]) {
    estimateSheetEditingIndex = index;
    estimateSheetActiveType = estimateSheetRecords[index].type;
    estimateSheetEditorState = estimateSheetCloneState(estimateSheetRecords[index].state);
  } else if (option.newBlank) {
    estimateSheetEditingIndex = null;
    estimateSheetEditorState = estimateSheetCreateState(estimateSheetActiveType);
  } else if (option.fromUpload && estimateSheetEditorState) {
    /* 업로드된 엑셀 값을 유지한 상태로 새 창을 연다. */
  } else {
    const firstIndex = estimateSheetRecords.findIndex(record => record.type === estimateSheetActiveType);
    if (firstIndex >= 0) {
      estimateSheetEditingIndex = firstIndex;
      estimateSheetEditorState = estimateSheetCloneState(estimateSheetRecords[firstIndex].state);
    } else {
      estimateSheetEditingIndex = null;
      estimateSheetEditorState = estimateSheetCreateState(estimateSheetActiveType);
    }
  }
  estimateSheetExcelActiveCell = { r: 1, c: 1 };
  const features = "popup=yes,width=1500,height=940,left=40,top=20,resizable=yes,scrollbars=yes";
  const win = window.open("", "CONCOST_ESTIMATE_EXCEL_WINDOW", features);
  if (!win) {
    if (!option.silent && typeof showToast === "function") showToast("팝업이 차단되었습니다. 브라우저에서 팝업 허용 후 다시 열어주세요.");
    return null;
  }
  estimateSheetExcelWindowRef = win;
  estimateSheetWriteExcelWindow(win);
  win.focus();
  closeEstimateSheetEditor();
  return win;
}


function newEstimateSheetRecord(type = estimateSheetActiveType) {
  estimateSheetActiveType = ESTIMATE_SHEET_TYPE_ORDER.includes(type) ? type : estimateSheetActiveType;
  estimateSheetEditingIndex = null;
  estimateSheetEditorState = estimateSheetCreateState(estimateSheetActiveType);
  estimateSheetExcelActiveCell = { r: 1, c: 1 };
  renderEstimateSheetManage();
  return openEstimateSheetExcelWindow(null, { newBlank: true });
}

function estimateSheetUploadExcelClick() {
  const input = document.getElementById("estimateSheetExcelUploadInput");
  if (input) input.click();
}

function estimateSheetEnsureXlsxLibrary(callback) {
  if (window.XLSX) { callback(); return; }
  const existing = document.getElementById("estimateSheetXlsxLibrary");
  if (existing) {
    existing.addEventListener("load", callback, { once: true });
    existing.addEventListener("error", () => showToast?.("엑셀 해석 라이브러리를 불러오지 못했습니다."), { once: true });
    return;
  }
  const script = document.createElement("script");
  script.id = "estimateSheetXlsxLibrary";
  script.src = "https://cdn.jsdelivr.net/npm/xlsx-js-style@1.2.0/dist/xlsx.bundle.js";
  script.onload = callback;
  script.onerror = () => showToast?.("엑셀 해석 라이브러리를 불러오지 못했습니다. 인터넷 연결 또는 CDN 접근을 확인해주세요.");
  document.head.appendChild(script);
}

function estimateSheetInferTypeFromFileName(name) {
  const text = String(name || "");
  if (text.includes("공내역")) return "공내역서";
  if (text.includes("설계예가")) return "설계예가";
  if (text.includes("공사비검증")) return "공사비검증";
  if (text.includes("개산")) return "개산견적";
  return estimateSheetActiveType;
}

function handleEstimateSheetExcelUpload(input) {
  const file = input?.files?.[0];
  if (!file) return;
  const targetType = estimateSheetInferTypeFromFileName(file.name);
  estimateSheetEnsureXlsxLibrary(() => {
    const reader = new FileReader();
    reader.onload = event => {
      try {
        const data = new Uint8Array(event.target.result);
        const workbook = XLSX.read(data, { type: "array", cellFormula: true, cellNF: true, cellStyles: true, sheetStubs: true, cellDates: true });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        estimateSheetApplyUploadedWorkbook(sheet, targetType, file.name);
        if (!estimateSheetExcelWindowRef || estimateSheetExcelWindowRef.closed) {
          openEstimateSheetExcelWindow(null, { fromUpload: true });
        }
      } catch (err) {
        console.error(err);
        showToast?.("엑셀 업로드 자료를 해석하지 못했습니다. 파일 형식을 확인해주세요.");
      } finally {
        input.value = "";
      }
    };
    reader.readAsArrayBuffer(file);
  });
}


/* 추천 구조 적용: 엑셀 불러오기는 원본 양식을 웹에 그대로 재현하려 하지 않고,
   현재 견적서 템플릿에 값/수식만 주입한다. 이렇게 하면 병합, 테두리, 행높이,
   열너비, 로고/도장, PDF/내보내기 기준이 항상 고정되어 형식 깨짐을 줄인다. */
function estimateSheetCellFromUploaded(sheet, r, c) {
  if (!sheet || !window.XLSX) return null;
  return sheet[XLSX.utils.encode_cell({ r: r - 1, c: c - 1 })] || null;
}

function estimateSheetUploadedCellText(sheet, r, c) {
  const cell = estimateSheetCellFromUploaded(sheet, r, c);
  if (!cell) return "";
  if (cell.f) return `=${String(cell.f).replace(/^=/, "")}`;
  return cell.w ?? cell.v ?? "";
}

function estimateSheetApplyTextToStateCell(state, r, c, text) {
  const obj = estimateSheetGetCellObj(state, r, c);
  const raw = String(text ?? "").replace(/\u00a0/g, " ").trim();
  if (!raw) {
    obj.value = "";
    obj.formula = "";
    obj.userFormula = false;
    return;
  }
  if (raw.startsWith("=")) {
    obj.formula = raw.slice(1);
    obj.value = "";
    obj.userFormula = true;
  } else {
    obj.formula = "";
    obj.userFormula = false;
    obj.value = /^-?[\d,]+(\.\d+)?$/.test(raw) ? Number(raw.replace(/,/g, "")) : raw;
  }
}

function estimateSheetUploadedUsedRows(sheet) {
  if (!sheet || !window.XLSX) return { maxRow: 1, maxCol: 1 };
  const ref = XLSX.utils.decode_range(sheet["!ref"] || "A1:A1");
  return { maxRow: ref.e.r + 1, maxCol: ref.e.c + 1 };
}

function estimateSheetFindUploadedRowByText(sheet, startRow, endRow, patterns) {
  const pats = patterns.map(p => new RegExp(p, "i"));
  for (let r = startRow; r <= endRow; r += 1) {
    let rowText = "";
    for (let c = 1; c <= 8; c += 1) rowText += String(estimateSheetUploadedCellText(sheet, r, c) || "").replace(/\s+/g, "");
    if (pats.some(p => p.test(rowText))) return r;
  }
  return null;
}

function estimateSheetCopyUploadedValueRange(sheet, state, fromRow, toRow, maxCol) {
  for (let r = fromRow; r <= toRow; r += 1) {
    for (let c = 1; c <= maxCol; c += 1) {
      const text = estimateSheetUploadedCellText(sheet, r, c);
      if (String(text ?? "") !== "") estimateSheetApplyTextToStateCell(state, r, c, text);
    }
  }
}

function estimateSheetBuildStateFromUploadedValues(sheet, type, fileName) {
  const spec = estimateSheetGetSpec(type);
  const used = estimateSheetUploadedUsedRows(sheet);
  const state = estimateSheetCreateState(type);
  state.fromUploadedWorkbook = true;
  state.importMode = "template-value-only";
  state.sourceFileName = fileName || "";
  state.maxCol = Math.max(state.maxCol || spec.maxCol || 15, spec.maxCol || 15);

  // 상단 기본정보와 우측 참고 영역은 위치가 고정된 값만 가져온다.
  estimateSheetCopyUploadedValueRange(sheet, state, 1, Math.min(12, used.maxRow), Math.min(15, state.maxCol));

  // 품목 영역은 업로드 파일에서 총계 행을 찾아 그 위까지 가져오되,
  // 웹 양식의 행/스타일은 템플릿 기준으로 유지한다.
  const uploadedTotalRow = estimateSheetFindUploadedRowByText(sheet, 13, used.maxRow, ["총계", "합계"]);
  const uploadedConditionRow = estimateSheetFindUploadedRowByText(sheet, 13, used.maxRow, ["견적조건"]);
  const itemEnd = uploadedTotalRow ? uploadedTotalRow - 1 : Math.min(19, used.maxRow);
  const baseItemEnd = 19;
  const extraItemRows = Math.max(0, itemEnd - baseItemEnd);
  state.itemExtraRows = extraItemRows;
  for (let i = 0; i < extraItemRows; i += 1) estimateSheetInsertRowIntoState(state, 19 + i);
  state.maxRow = Math.max(state.maxRow, (spec.maxRow || 33) + extraItemRows);
  estimateSheetCopyUploadedValueRange(sheet, state, 13, Math.min(itemEnd, used.maxRow), Math.min(7, state.maxCol));

  // 총계 이하 영역은 템플릿 위치에 맞게 다시 배치한다. 업로드 파일에 행이 추가되어도
  // 불필요한 세로선/공백/정렬 깨짐이 생기지 않도록 양식 위치는 고정한다.
  const totalTarget = 20 + extraItemRows;
  if (uploadedTotalRow) {
    for (let c = 1; c <= 7; c += 1) {
      const text = estimateSheetUploadedCellText(sheet, uploadedTotalRow, c);
      if (String(text ?? "") !== "") estimateSheetApplyTextToStateCell(state, totalTarget, c, text);
    }
  }

  const conditionSource = uploadedConditionRow || (uploadedTotalRow ? uploadedTotalRow + 1 : 21);
  const conditionTarget = 21 + extraItemRows;
  let writtenConditionRows = 0;
  for (let rr = 0; rr < 12 && writtenConditionRows < 8; rr += 1) {
    const srcR = conditionSource + rr;
    const rowText = estimateSheetRowTextFromUploaded(sheet, srcR, 7);
    if (srcR !== uploadedTotalRow && (rowText.includes("총계") || rowText.includes("합계"))) continue;
    const dstR = conditionTarget + writtenConditionRows;
    if (dstR > state.maxRow) {
      state.maxRow = dstR;
      state.rowHeights.push(26);
    }
    for (let c = 1; c <= 7; c += 1) {
      const text = estimateSheetUploadedCellText(sheet, srcR, c);
      if (String(text ?? "") !== "") estimateSheetApplyTextToStateCell(state, dstR, c, text);
    }
    writtenConditionRows += 1;
  }

  // 우측 참고/검증 영역은 템플릿이 허용하는 범위에서 값만 가져온다.
  for (let r = 1; r <= Math.min(used.maxRow, state.maxRow); r += 1) {
    for (let c = 8; c <= Math.min(used.maxCol, state.maxCol); c += 1) {
      const text = estimateSheetUploadedCellText(sheet, r, c);
      if (String(text ?? "") !== "") estimateSheetApplyTextToStateCell(state, r, c, text);
    }
  }

  estimateSheetNormalizeUploadedFormat(state);
  estimateSheetApplyManualOverrides(state);
  state.templateValueOnly = true;
  return state;
}

function estimateSheetInsertRowIntoState(state, afterRow) {
  const newCells = {};
  Object.entries(state.cells || {}).forEach(([key, val]) => {
    const [r, c] = key.split(":").map(Number);
    newCells[estimateSheetCellKey(r > afterRow ? r + 1 : r, c)] = val;
  });
  state.cells = newCells;
  state.maxRow += 1;
  state.rowHeights.splice(afterRow, 0, state.rowHeights[afterRow - 1] || 26);
  if (Array.isArray(state.merges)) {
    state.merges = state.merges.map(m => m.map((v, idx) => (idx === 0 || idx === 2) && v > afterRow ? v + 1 : v));
  }
}

function estimateSheetApplyUploadedWorkbook(sheet, type, fileName) {
  if (!sheet) return;
  const previousEditingIndex = estimateSheetEditingIndex;
  estimateSheetActiveType = ESTIMATE_SHEET_TYPE_ORDER.includes(type) ? type : estimateSheetActiveType;
  const state = estimateSheetBuildStateFromUploadedValues(sheet, estimateSheetActiveType, fileName);
  estimateSheetEditorState = state;
  estimateSheetEditingIndex = previousEditingIndex;
  estimateSheetExcelActiveCell = { r: 1, c: 1 };
  renderEstimateSheetManage();
  estimateSheetRenderExcelWindow();
  showToast?.("엑셀 파일의 값/수식만 현재 견적서 양식에 반영했습니다. 확인 후 견적서 저장을 누르면 견적서관리와 기간별 견적서관리가 연결됩니다.");
}


function estimateSheetBuildPrintableGridHtml(state) {
  const spec = estimateSheetGetSpec(state.type);
  const merge = estimateSheetMergeInfoForState(spec, state);
  const cols = state.colWidths || spec.cols;
  const rows = state.rowHeights || spec.rows;
  const maxRow = state.maxRow || spec.maxRow;
  const maxCol = spec.printCols || 7;
  const colGroup = `<colgroup>${Array.from({ length: maxCol }, (_, i) => `<col style="width:${cols[i] || 64}px">`).join("")}</colgroup>`;
  const body = Array.from({ length: maxRow }, (_, ri) => {
    const r = ri + 1;
    const h = rows[ri] || 20;
    const cells = Array.from({ length: maxCol }, (_, ci) => {
      const c = ci + 1;
      const key = estimateSheetCellKey(r, c);
      if (merge.skips.has(key)) return "";
      const spanRaw = merge.starts[key] || { rowspan: 1, colspan: 1 };
      const span = {
        rowspan: Math.min(spanRaw.rowspan || 1, Math.max(1, maxRow - r + 1)),
        colspan: Math.min(spanRaw.colspan || 1, Math.max(1, maxCol - c + 1))
      };
      const tmpl = estimateSheetCellTemplate(spec, estimateSheetTemplateRowForState(state, r), c);
      const obj = estimateSheetGetCellObj(state, r, c);
      const displayed = estimateSheetDisplayValue(state, r, c);
      const overflowClass = estimateSheetShouldOverflowText(state, r, c, displayed, span) ? " printable-overflow" : "";
      return `<td class="printable-cell${overflowClass}" ${span.rowspan > 1 ? `rowspan="${span.rowspan}"` : ""} ${span.colspan > 1 ? `colspan="${span.colspan}"` : ""} style="${estimateSheetHtml(estimateSheetCellEffectiveStyle(obj, tmpl))};height:${h}px">${estimateSheetHtml(displayed)}</td>`;
    }).join("");
    return `<tr style="height:${h}px">${cells}</tr>`;
  }).join("");
  return `<table class="printable-grid">${colGroup}<tbody>${body}</tbody></table>`;
}

function estimateSheetBuildPrintableImagesHtml(state) {
  const spec = estimateSheetGetSpec(state.type);
  return (spec.images || []).map((img, i) => {
    const pos = estimateSheetImagePosition(spec, img, state);
    return `<img class="printable-image" src="${img.data}" alt="견적서 이미지 ${i + 1}" style="left:${pos.left}px;top:${pos.top}px;width:${pos.width}px;height:${pos.height}px">`;
  }).join("");
}

function estimateSheetPrintCurrentPdf() {
  if (!estimateSheetEditorState) estimateSheetEditorState = estimateSheetCreateState(estimateSheetActiveType);
  const state = estimateSheetEditorState;
  const spec = estimateSheetGetSpec(state.type);
  const cols = state.colWidths || spec.cols;
  const rows = state.rowHeights || spec.rows;
  const printCols = spec.printCols || 7;
  const printRows = Math.max(state.maxRow || 33, spec.maxRow || 33);
  const sheetWidth = cols.slice(0, printCols).reduce((sum, v) => sum + (Number(v) || 64), 0);
  const sheetHeight = rows.slice(0, printRows).reduce((sum, v) => sum + (Number(v) || 20), 0);
  const contentW = 642;
  const contentH = 1040;
  const printScale = Math.min(1, contentW / Math.max(1, sheetWidth), contentH / Math.max(1, sheetHeight));
  const fileTitle = `CONCOST_${estimateSheetActiveType}_${new Date().toISOString().slice(0,10).replace(/-/g, "")}`;
  const printWin = window.open("", "CONCOST_ESTIMATE_PDF_PRINT", "width=900,height=1000,left=80,top=30,resizable=yes,scrollbars=yes");
  if (!printWin) {
    showToast?.("팝업이 차단되었습니다. 브라우저에서 팝업 허용 후 다시 시도해주세요.");
    return;
  }
  const css = `
    @page{size:A4 portrait;margin:0;}
    *{box-sizing:border-box;}
    html,body{margin:0;padding:0;background:#e5e7eb;font-family:'Malgun Gothic','맑은 고딕',Arial,sans-serif;color:#111827;}
    .print-page{width:794px;height:1123px;margin:0 auto;background:#fff;padding:28px 22px 22px;position:relative;overflow:hidden;}
    .print-frame{width:100%;height:100%;position:relative;border:none;padding:0;}
    .print-sheet-viewport{position:relative;width:100%;height:100%;overflow:visible;}
    .print-sheet{position:relative;width:${sheetWidth}px;height:${sheetHeight}px;margin:0 auto;transform:scale(var(--print-scale));transform-origin:top center;}
    .printable-grid{border-collapse:collapse;table-layout:fixed;width:${sheetWidth}px;background:transparent;position:absolute;left:0;top:0;z-index:2;}
    .printable-cell{border:none;min-height:0;line-height:1.25;white-space:nowrap;word-break:normal;text-overflow:clip;overflow:visible;position:relative;vertical-align:middle;background:transparent;font-size:11pt;}
    .printable-cell[style*="font-size:28pt"],.printable-cell[style*="font-size: 28pt"]{font-size:28pt!important;}
    .printable-overflow{z-index:30!important;}
    .printable-image{position:absolute;object-fit:contain;pointer-events:none;z-index:3;}
    @media print{html,body{background:#fff;}.print-page{margin:0;padding:28px 22px 22px;box-shadow:none;} .no-print{display:none!important;}}
  `;
  const html = `<!doctype html><html><head><meta charset="utf-8"><title>${estimateSheetHtml(fileTitle)}</title><style>${css}</style></head><body>
    <div class="print-page" style="--print-scale:${printScale}">
      <div class="print-frame">
        <div class="print-sheet-viewport"><div class="print-sheet">${estimateSheetBuildPrintableGridHtml(state)}${estimateSheetBuildPrintableImagesHtml(state)}</div></div>
        <div class="print-footer"></div>
      </div>
    </div>
    <script>window.onload=function(){setTimeout(function(){window.focus();window.print();},250);};<\/script>
  </body></html>`;
  printWin.document.open();
  printWin.document.write(html);
  printWin.document.close();
}

const estimateSheetInlineEditorOpen = openEstimateSheetEditor;
openEstimateSheetEditor = function(index = null) {
  return openEstimateSheetExcelWindow(index);
};

const estimateSheetOriginalSetType = setEstimateSheetType;
setEstimateSheetType = function(type) {
  estimateSheetActiveType = ESTIMATE_SHEET_TYPE_ORDER.includes(type) ? type : "개산견적";
  closeEstimateSheetEditor();
  renderEstimateSheetManage();
  if (estimateSheetExcelWindowRef && !estimateSheetExcelWindowRef.closed) openEstimateSheetExcelWindow(null, { silent: true });
};

function autoOpenEstimateSheetExcelWindowOnce() {
  /* 2026-05-23 수정: 견적서관리 화면 진입 시 새 창을 자동으로 열지 않는다.
     새 창은 목록 행 클릭, [새로만들기], [엑셀 업로드] 동작에서만 열린다. */
  estimateSheetExcelAutoOpenTried = true;
}

